import React, {useReducer} from "react";
import {useHistory} from "react-router-dom";

import {backendUrl} from "../static/js/const";
import {authAxios} from "../static/js/util";
import globalContext from "./globalContext";
import {globalReducer, LOGIN, LOGOUT, SET_BOARD_CONTEXT} from "./globalReducer";

const GlobalProvider = (props) => {
  const history = useHistory();
  const [globalState, dispatch] = useReducer(globalReducer, {
    authUser: null,
    checkedAuth: false,
    board: null,
    setBoard: null,
  });

  const login = async (resData) => {
    localStorage.setItem("accessToken", resData.accessToken);
    localStorage.setItem("refreshToken", resData.refreshToken);
    const user = {id: resData.id, username: resData.username, full_name: resData.username};
    localStorage.setItem("user", JSON.stringify(user));

    dispatch({type: LOGIN, user});
    history.push("/");
  };

  const checkAuth = async () => {
    const token = localStorage.getItem("accessToken");
    const storedUser = localStorage.getItem("user");
    if (token && storedUser) {
      dispatch({type: LOGIN, user: JSON.parse(storedUser)});
    } else {
      dispatch({type: LOGOUT});
    }
  };

  const logout = () => {
    dispatch({type: LOGOUT});
    history.push("/login");
  };

  const setBoardContext = (board, setBoard) => {
    dispatch({type: SET_BOARD_CONTEXT, board, setBoard});
  };

  return (
    <globalContext.Provider
      value={{
        authUser: globalState.authUser,
        checkedAuth: globalState.checkedAuth,
        board: globalState.board,
        setBoard: globalState.setBoard,
        checkAuth,
        login,
        logout,
        setBoardContext,
      }}
    >
      {props.children}
    </globalContext.Provider>
  );
};

export default GlobalProvider;
